import{_ as s,C as n,o as l,c as o,E as r,w as a,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Netherlands Healthcare","description":"Healthcare and HRT access for transgender people in the Netherlands","frontmatter":{"layout":"doc","title":"Netherlands Healthcare","description":"Healthcare and HRT access for transgender people in the Netherlands"},"headers":[],"relativePath":"europe/netherlands/healthcare.md","filePath":"europe/netherlands/healthcare.md","lastUpdated":null}'),h={name:"europe/netherlands/healthcare.md"};function c(g,e,p,u,m,y){const t=n("Badge");return l(),o("div",null,[r(t,{variant:"green"},{default:a(()=>[...e[0]||(e[0]=[i("Informed Consent Model",-1)])]),_:1}),r(t,{variant:"blue"},{default:a(()=>[...e[1]||(e[1]=[i("Public Healthcare System",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="healthcare-in-the-netherlands" tabindex="-1">Healthcare in the Netherlands <a class="header-anchor" href="#healthcare-in-the-netherlands" aria-label="Permalink to &quot;Healthcare in the Netherlands&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>The Netherlands has a well-established system for gender affirming healthcare, primarily through specialised <strong>gender teams at university medical centres (UMCs)</strong>. The country follows a stepwise protocol that has evolved toward an informed consent model, though some structured assessment remains.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><p>Hormone therapy is accessed through gender teams at UMCs. While the Netherlands historically used a gatekeeping model, the approach has become increasingly patient-led:</p><ul><li>Initial intake with a psychologist/psychiatrist (typically 1-3 sessions)</li><li>No longer requires full RLE (real life experience)</li><li>Endocrine assessment and hormone initiation</li><li>Follow-up monitoring every 3-6 months initially</li><li>Typical wait times: 4-12 months (varies by clinic)</li></ul><h3 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th><th>Languages</th><th>Wait Times</th></tr></thead><tbody><tr><td>Amsterdam UMC - Gender Team</td><td>Amsterdam</td><td>Full spectrum: HRT, surgery, psych</td><td>NL, EN</td><td>6-12 months</td></tr><tr><td>UMC Groningen - Gender Team</td><td>Groningen</td><td>HRT, surgery referrals, psych</td><td>NL, EN</td><td>4-10 months</td></tr><tr><td>Radboud UMC</td><td>Nijmegen</td><td>HRT, psychological support</td><td>NL, EN</td><td>5-10 months</td></tr><tr><td>PsyTrans (private)</td><td>Nationwide (online)</td><td>Fast-track assessment, referrals</td><td>NL, EN</td><td>2-4 months</td></tr></tbody></table><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>The Netherlands has one of the most advanced gender surgery programmes in Europe, particularly at Amsterdam UMC:</p><ul><li><strong>Chest/breast surgery (top surgery)</strong> — Widely available, covered by insurance</li><li><strong>Genital surgery (bottom surgery)</strong> — Amsterdam UMC is a world-leading centre</li><li><strong>Facial feminisation surgery</strong> — Partial insurance coverage</li><li><strong>Voice surgery</strong> — Available but limited coverage</li><li><strong>Hysterectomy/oophorectomy</strong> — Covered</li></ul><p>Insurance (basisverzekering) covers gender affirming treatments under the basic healthcare package for those with a diagnosis of gender dysphoria.</p><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>As an EU member state, the Netherlands accepts prescriptions from other EU/EEA countries:</p><ul><li>Valid for up to 30 days</li><li>English-language prescriptions recommended</li><li>Dutch pharmacies may require a Dutch GP to re-prescribe for ongoing treatment</li></ul><table tabindex="0"><thead><tr><th>Medication</th><th>Typical Cost (insured)</th><th>Pharmacy Availability</th></tr></thead><tbody><tr><td>Oestradiol (oral/gel/patches)</td><td>Covered/€5-15 eigen risico</td><td>Widely available</td></tr><tr><td>Testosterone (gel/injectable)</td><td>Covered/€10-25 eigen risico</td><td>Widely available</td></tr><tr><td>Cyproterone acetate</td><td>Covered/€8-15 eigen risico</td><td>Available</td></tr><tr><td>GnRH agonists</td><td>Covered (specialist)</td><td>Specialist pharmacy</td></tr></tbody></table><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li><strong>Gender team psychologists</strong> — Integrated into UMC care</li><li><strong>Transgender Network Nederland</strong> — Peer support</li><li><strong>Private gender therapists</strong> — Faster access, costs €80-150/session</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Transvisie</strong> — Trans health information: <a href="https://www.transvisie.nl/" target="_blank" rel="noreferrer">transvisie.nl</a></li><li><strong>Amsterdam UMC Gender Team</strong> — <a href="https://www.amsterdamumc.org/" target="_blank" rel="noreferrer">amsterdamumc.org</a></li><li><strong>UMC Groningen Gender Team</strong> — <a href="https://www.umcg.nl/" target="_blank" rel="noreferrer">umcg.nl</a></li><li><strong>Zorginstituut Nederland</strong> — Health insurance information: <a href="https://www.zorginstituutnederland.nl/" target="_blank" rel="noreferrer">zorginstituutnederland.nl</a></li></ul>',20))])}const v=s(h,[["render",c]]);export{b as __pageData,v as default};
